  private void OpenJoinPasswordDialog()
  {
    new DialogWindow(Loc.GetString("pubg-mini-lobby-password-title"), new List<QuickDialogEntry>()
    {
      new QuickDialogEntry("password", QuickDialogEntryType.ShortText, Loc.GetString("pubg-mini-lobby-password"))
    }).OnConfirmed += (Action<Dictionary<string, string>>) (values =>
    {
      string str;
      if (!values.TryGetValue("password", out str))
        return;
      Action<int, string> onJoinLobby = this.OnJoinLobby;
      if (onJoinLobby == null)
        return;
      onJoinLobby(this._currentLobbyId, str);
    });
  }

  private void OpenPasswordDialog()
  {
    if (this._currentLobbyId == 0)
      return;
    new DialogWindow(Loc.GetString("pubg-mini-lobby-password-title"), new List<QuickDialogEntry>()
    {
      new QuickDialogEntry("password", QuickDialogEntryType.ShortText, Loc.GetString("pubg-mini-lobby-password"))
    }).OnConfirmed += (Action<Dictionary<string, string>>) (values =>
    {
      string str;
      if (!values.TryGetValue("password", out str))
        return;
      MiniGameLobbyStateMessage currentLobbyState = this._currentLobbyState;
      bool flag = currentLobbyState != null && currentLobbyState.IsLocked;
      Action<int, bool, string, bool> onSetLock = this.OnSetLock;
      if (onSetLock == null)
        return;
      onSetLock(this._currentLobbyId, flag, str, true);
    });
  }

  private void SendChat()
  {
    if (this._currentLobbyId == 0)
      return;
    if (this._currentLobbyState != null && !this.IsLocalUserInLobby(this._currentLobbyState))
    {
      this.ErrorLabel.Text = Loc.GetString("pubg-mini-lobby-chat-join-required");
      ((Control) this.ErrorLabel).Visible = true;
    }
    else
    {
      string str = this.ChatInput.Text.Trim();
      if (str.Length == 0)
        return;
      this.ChatInput.Text = string.Empty;
      Action<int, string> onSendChat = this.OnSendChat;
      if (onSendChat == null)
        return;
      onSendChat(this._currentLobbyId, str);
    }
  }

