  private bool IsLocalUserInLobby(MiniGameLobbyStateMessage msg)
  {
    NetUserId? userId = ((ISharedPlayerManager) this._playerManager).LocalSession?.UserId;
    return userId.HasValue && msg.Players.Any<MiniGameLobbyPlayerInfo>((Func<MiniGameLobbyPlayerInfo, bool>) (p =>
    {
      NetUserId userId1 = p.UserId;
      NetUserId? nullable = userId;
      return nullable.HasValue && NetUserId.op_Equality(userId1, nullable.GetValueOrDefault());
    }));
  }

  private bool IsLocalUserLeader(MiniGameLobbyStateMessage msg)
  {
    NetUserId? userId = ((ISharedPlayerManager) this._playerManager).LocalSession?.UserId;
    return userId.HasValue && msg.Players.Any<MiniGameLobbyPlayerInfo>((Func<MiniGameLobbyPlayerInfo, bool>) (p =>
    {
      NetUserId userId1 = p.UserId;
      NetUserId? nullable = userId;
      return (nullable.HasValue ? (NetUserId.op_Equality(userId1, nullable.GetValueOrDefault()) ? 1 : 0) : 0) != 0 && p.IsLeader;
    }));
  }

